+
+/// Generate hashlib.new(name, data?) -> HashObject
+pub fn genNew(self: *NativeCodegen, args: []ast.Node) CodegenError!void {
+    if (args.len == 0) return;
+    try self.emit("try hashlib.new(");
+    try self.genExpr(args[0]);
+    try self.emit(")");
+}

